export enum UserRole {
  SUPER_ADMIN = 'super_admin',
  FUNCIONARIO = 'funcionario',
  CUERPO_TECNICO = 'cuerpo_tecnico',
  PETROLERA = 'petrolera',
  COMPANY = 'company',
  EMPRESA_LOCAL = 'empresa_local',
  PERSONA = 'persona',
  COMUNICACION = 'comunicacion',
  COMUNIDAD = 'comunidad'
}

export type Language = 'es' | 'en' | 'fr';

export interface User {
  id: string;
  email: string;
  role: UserRole;
  name: string;
  avatar?: string;
  isOnline: boolean;
  permissions: string[];
}

export interface Company {
  id: string;
  name: string;
  taxId: string;
  type: 'local' | 'international';
  sector: string[];
  status: 'certified' | 'pending' | 'expired' | 'rejected';
  rating: number;
  badges: BadgeType[];
  certificationLevel: 'basic' | 'standard' | 'premium' | 'elite';
  complianceScore: number;
  nationalEmployeeCount: number;
  totalEmployeeCount: number;
  localSpendPercentage: number;
  auditHistory: AuditLog[];
}

export interface AuditLog {
  id: string;
  date: string;
  officer: string;
  result: 'passed' | 'failed' | 'conditional';
  notes: string;
}

export enum BadgeType {
  NATIONAL_CONTENT = 'national_content',
  COMPLIANT = 'compliant',
  TOP_EMPLOYER = 'top_employer',
  ESG_COMMITTED = 'esg_committed'
}

export interface Opportunity {
  id: string;
  title: Record<Language, string>;
  description: Record<Language, string>;
  category: string;
  budget: number;
  deadline: string;
  status: 'published' | 'closed' | 'awarded' | 'under_review';
  petroleraId: string;
  location: string;
  requirements: string[];
}

export interface Application {
  id: string;
  opportunityId: string;
  companyId: string;
  status: 'submitted' | 'under_review' | 'shortlisted' | 'awarded' | 'rejected';
  submittedAt: string;
  documents: string[];
  feedback?: string;
}

export interface JobOffer {
  id: string;
  title: Record<Language, string>;
  companyId: string;
  location: string;
  salary?: string;
  tags: string[];
  postedAt: string;
  description: Record<Language, string>;
  category: string;
}

export interface CandidateProfile {
  userId: string;
  skills: string[];
  experience: WorkExperience[];
  cvUrl?: string;
  savedJobs: string[];
}

export interface WorkExperience {
  company: string;
  position: string;
  duration: string;
  description: string;
}

export interface SocialProject {
  id: string;
  title: Record<Language, string>;
  description: Record<Language, string>;
  impact: string;
  location: string;
  image: string;
  petroleraId: string;
  status: 'proposed' | 'active' | 'completed';
}

export interface Message {
  id: string;
  conversationId: string;
  senderId: string;
  text: string;
  timestamp: Date;
  isRead: boolean;
}

export interface SystemSettings {
  maintenanceMode: boolean;
  registrationEnabled: boolean;
  portalVersion: string;
  lastBackup: string;
}

