          className="fixed inset-0 bg-slate-950/60 backdrop-blur-sm z-[55] xl:hidden transition-opacity animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <div className="flex-1 flex flex-col min-w-0">
        {/* Header - Ahora recibe toggleSidebar */}
        <DashboardHeader onToggleSidebar={toggleSidebar} />

        {/* Simulador de Entorno */}
        <div className="bg-white/90 border-b border-slate-100 px-6 md:px-10 py-4 flex flex-col sm:flex-row items-center justify-between shrink-0 gap-4">
           <div className="flex items-center w-full sm:w-auto">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mr-4 hidden sm:block">Simulador:</span>
              <select 
                value={currentUserId}
                onChange={handleRoleChange}
                className="w-full sm:w-auto bg-slate-100 text-[10px] font-black uppercase px-4 py-2.5 rounded-xl border-none outline-none focus:ring-2 focus:ring-blue-600 cursor-pointer shadow-sm"
              >
                {MOCK_USERS.map(u => (
                  <option key={u.id} value={u.id}>{u.name} — {t(`roles.${u.role}`).toUpperCase()}</option>
                ))}
              </select>
           </div>
           <div className="flex items-center space-x-4">
              <span className={`w-2 h-2 rounded-full ${currentUser.isOnline ? 'bg-green-500' : 'bg-slate-400'}`}></span>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Entorno Sincronizado</span>
           </div>
        </div>

        <main className="flex-1 overflow-y-auto p-6 md:p-12 custom-scrollbar">
          <Routes>
            <Route path="super_admin/overview" element={<div className="space-y-12"><header><h1 className="text-3xl md:text-4xl font-black tracking-tighter">{t('dashboard.overview')}</h1></header><StatGrid stats={[{ label: t('dashboard.stats.total_users'), value: "3.2k" }, { label: "Servidores", value: "Online" }, { label: "Tráfico Hoy", value: "1.4k" }, { label: "Alertas", value: "0" }]} /><AdminUserManagement /></div>} />
            <Route path="super_admin/users" element={<AdminUserManagement />} />
            <Route path="super_admin/companies" element={<CompanyAudit />} />
            <Route path="funcionario/overview" element={<div className="space-y-12"><header><h1 className="text-4xl font-black tracking-tighter">Gestión Ministerial</h1></header><StatGrid stats={[{label: "Empresas en Revisión", value: "12"}, {label: "Licitaciones Activas", value: "45"}]} /><AdminUserManagement /></div>} />
            <Route path="*/lex" element={<div className="h-full max-w-5xl"><LexAssistant /></div>} />
            <Route path="*/messages" element={<div className="h-full flex items-center justify-center p-4"><ChatWindow currentUser={currentUser} recipient={MOCK_USERS[1]} /></div>} />
            <Route path="*" element={<Navigate to={`overview`} />} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

export default Dashboard;

